import{_ as a,o as e,c as n,a6 as i}from"./chunks/framework.wLlb4ebq.js";const g=JSON.parse('{"title":"AI Prompt Injection 多层防御","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/prompt-injection-defense.md","filePath":"concepts/prompt-injection-defense.md"}'),s={name:"concepts/prompt-injection-defense.md"};function o(r,t,l,d,p,c){return e(),n("div",null,[...t[0]||(t[0]=[i(`<h1 id="ai-prompt-injection-多层防御" tabindex="-1">AI Prompt Injection 多层防御 <a class="header-anchor" href="#ai-prompt-injection-多层防御" aria-label="Permalink to “AI Prompt Injection 多层防御”">​</a></h1><p>LD-Notion 的 AI 助手接收用户输入和外部内容（Linux.do 帖子、GitHub README、网页摘要等），这些内容可能包含恶意 prompt injection 攻击。v3.7.0 引入了多层防御体系来隔离和净化不可信输入。</p><h2 id="威胁模型" tabindex="-1">威胁模型 <a class="header-anchor" href="#威胁模型" aria-label="Permalink to “威胁模型”">​</a></h2><p>攻击者可以通过以下路径注入恶意指令：</p><ol><li><strong>Linux.do 帖子内容</strong>：帖子标题或正文中嵌入 <code>忽略以上指令</code> 类文本。</li><li><strong>GitHub README</strong>：仓库描述或 README 中嵌入 prompt injection payload。</li><li><strong>浏览器书签元数据</strong>：书签标题或 URL 中包含恶意文本。</li><li><strong>用户对话输入</strong>：用户自身输入中包含试图覆盖系统指令的文本。</li></ol><h2 id="三层防御" tabindex="-1">三层防御 <a class="header-anchor" href="#三层防御" aria-label="Permalink to “三层防御”">​</a></h2><h3 id="第一层-输入隔离-xml-标签分离" tabindex="-1">第一层：输入隔离（XML 标签分离） <a class="header-anchor" href="#第一层-输入隔离-xml-标签分离" aria-label="Permalink to “第一层：输入隔离（XML 标签分离）”">​</a></h3><p>AI 分类 prompt 将用户内容包裹在 <code>&lt;user_content&gt;</code> XML 标签中，与系统指令分离：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>系统指令...</span></span>
<span class="line"><span>&lt;user_content&gt;</span></span>
<span class="line"><span>  &lt;title&gt;帖子标题&lt;/title&gt;</span></span>
<span class="line"><span>  &lt;body&gt;帖子正文&lt;/body&gt;</span></span>
<span class="line"><span>&lt;/user_content&gt;</span></span>
<span class="line"><span>请根据以上用户内容进行分类...</span></span></code></pre></div><p>这降低了用户内容中的 <code>忽略以上指令</code> 类文本被 AI 误判为系统指令的风险。</p><h3 id="第二层-输出净化-escapehtml-safemarkdown" tabindex="-1">第二层：输出净化（escapeHtml + safeMarkdown） <a class="header-anchor" href="#第二层-输出净化-escapehtml-safemarkdown" aria-label="Permalink to “第二层：输出净化（escapeHtml + safeMarkdown）”">​</a></h3><p>ChatUI 实现两个净化辅助函数：</p><ul><li><strong><code>escapeHtml</code></strong>：使用浏览器原生 <code>textContent→innerHTML</code> 机制转义 <code>&lt;</code>、<code>&gt;</code>、<code>&amp;</code>、<code>&quot;</code>，防止 HTML/JS 注入。</li><li><strong><code>safeMarkdown</code></strong>：先转义全部 HTML，再选择性恢复安全 Markdown 格式（粗体 <code>**</code>、换行），防止注入的 HTML/JS 在聊天 UI 中渲染。</li></ul><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>原始 AI 回复：&lt;script&gt;alert(&#39;xss&#39;)&lt;/script&gt;**重要**</span></span>
<span class="line"><span>escapeHtml 后：&amp;lt;script&amp;gt;alert(&#39;xss&#39;)&amp;lt;/script&amp;gt;**重要**</span></span>
<span class="line"><span>safeMarkdown 后：&amp;lt;script&amp;gt;alert(&#39;xss&#39;)&amp;lt;/script&amp;gt;&lt;strong&gt;重要&lt;/strong&gt;</span></span></code></pre></div><h3 id="第三层-ui-全局转义" tabindex="-1">第三层：UI 全局转义 <a class="header-anchor" href="#第三层-ui-全局转义" aria-label="Permalink to “第三层：UI 全局转义”">​</a></h3><p>所有用户可控文本在插入 HTML 前统一经过 <code>Utils.escapeHtml</code> 转义，覆盖 50+ 处拼接点：</p><ul><li>数据库名称、页面标题</li><li>错误消息、书签标题</li><li>标签、文件名、报告预览</li><li>来源类型、书签路径</li></ul><h2 id="与-operationguard-的协作" tabindex="-1">与 OperationGuard 的协作 <a class="header-anchor" href="#与-operationguard-的协作" aria-label="Permalink to “与 OperationGuard 的协作”">​</a></h2><p>Prompt injection 防御和 OperationGuard 在不同层面工作：</p><table tabindex="0"><thead><tr><th>防御层</th><th>防御目标</th><th>作用阶段</th></tr></thead><tbody><tr><td>XML 标签隔离</td><td>防止恶意内容劫持 AI 意图</td><td>AI 请求构建</td></tr><tr><td>输出净化</td><td>防止恶意内容通过 UI 渲染</td><td>AI 回复展示</td></tr><tr><td>UI 全局转义</td><td>防止恶意内容通过 UI 拼接</td><td>DOM 渲染</td></tr><tr><td>OperationGuard</td><td>防止未授权写入</td><td>写入执行</td></tr></tbody></table><p>四层防御互补：即使 prompt injection 成功影响了 AI 意图，OperationGuard 仍会在写入前检查权限；即使写入被允许，输出净化和 UI 转义仍会阻止恶意内容在 UI 中渲染。</p><h2 id="已知局限" tabindex="-1">已知局限 <a class="header-anchor" href="#已知局限" aria-label="Permalink to “已知局限”">​</a></h2><ul><li>XML 标签隔离依赖 AI 模型正确理解标签语义，部分模型可能在复杂嵌套场景下混淆标签边界。</li><li><code>safeMarkdown</code> 当前仅恢复粗体和换行，链接、代码块等格式被转义后不再渲染。</li><li>Extension 版本中 background service worker 的 URL 白名单使用简单字符串匹配，存在 SSRF 绕过风险（详见 <a href="/LD-Notion/extension/architecture">Extension Architecture</a>）。</li></ul>`,23)])])}const m=a(s,[["render",o]]);export{g as __pageData,m as default};
